import csv, io

csv_text = 'category,amount\nfood,10\nfood,5\ntoys,8\nfood,bad\ntoys,-3\n'
reader = csv.DictReader(io.StringIO(csv_text))

totals = {}
for row in reader:
    try:
        amount = int(row['amount'])
    except ValueError:
        continue
    if amount <= 0:
        continue
    totals[row['category']] = totals.get(row['category'], 0) + amount

print(totals)
